def make_normalizer(mode):
    if mode == 'digits':
        def digits(s):
            return "".join(ch for ch in s if ch.isdigit())
        return digits
    if mode == 'lower':
        def lower(s):
            return s.strip().lower()
        return lower
    raise ValueError(mode)
d = make_normalizer('digits')
lo = make_normalizer('lower')
print(d('A-1-B-2'), lo('  Hola '))
